  1	import { type FC, useCallback, useState } from 'react';
  2	import { encode } from 'js-base64';
  3	import { FormGroupWithHelpText } from 'src/components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  4	import { OpenstackSecretFieldsId } from 'src/providers/utils/constants';
  5	import { useForkliftTranslation } from 'src/utils/i18n';
  6	
  7	import { Button, ButtonVariant, InputGroup, TextInput } from '@patternfly/react-core';
  8	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
  9	import type { ValidationMsg } from '@utils/validation/Validation';
 10	
 11	import { getDecodedValue } from './utils/getDecodedValue';
 12	import { openstackSecretFieldValidator } from './utils/openstackSecretFieldValidator';
 13	import type { CredentialsEditModeByTypeProps, onChangeFactoryType } from './utils/types';
 14	import OpenstackDomainEditItem from './OpenstackDomainEditItem';
 15	import OpenstackProjectEditItem from './OpenstackProjectEditItem';
 16	import OpenstackRegionEditItem from './OpenstackRegionEditItem';
 17	import OpenstackUsernameEditItem from './OpenstackUsernameEditItem';
 18	
 19	const TokenWithUsernameSecretFieldsEditSection: FC<CredentialsEditModeByTypeProps> = ({
 20	  onNewSecretChange,
 21	  secret,
 22	}) => {
 23	  const { t } = useForkliftTranslation();
 24	
 25	  const token = getDecodedValue(secret?.data?.token);
 26	  const username = getDecodedValue(secret?.data?.username);
 27	  const regionName = getDecodedValue(secret?.data?.regionName);
 28	  const projectName = getDecodedValue(secret?.data?.projectName);
 29	  const domainName = getDecodedValue(secret?.data?.domainName);
 30	
 31	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 32	  const [tokenValidation, setTokenValidation] = useState<ValidationMsg>(
 33	    openstackSecretFieldValidator(OpenstackSecretFieldsId.Token, token!),
 34	  );
 35	  const [usernameValidation, setUsernameValidation] = useState<ValidationMsg>(
 36	    openstackSecretFieldValidator(OpenstackSecretFieldsId.Username, username!),
 37	  );
 38	  const [regionNameValidation, setRegionNameValidation] = useState<ValidationMsg>(
 39	    openstackSecretFieldValidator(OpenstackSecretFieldsId.RegionName, regionName!),
 40	  );
 41	  const [projectNameValidation, setProjectNameValidation] = useState<ValidationMsg>(
 42	    openstackSecretFieldValidator(OpenstackSecretFieldsId.ProjectName, projectName!),
 43	  );
 44	  const [domainNameValidation, setDomainNameValidation] = useState<ValidationMsg>(
 45	    openstackSecretFieldValidator(OpenstackSecretFieldsId.DomainName, domainName!),
 46	  );
 47	
 48	  const handleChange = useCallback(
 49	    (id: OpenstackSecretFieldsId, value: string) => {
 50	      const validationState = openstackSecretFieldValidator(id, value);
 51	
 52	      if (id === OpenstackSecretFieldsId.Token) setTokenValidation(validationState);
 53	      if (id === OpenstackSecretFieldsId.Username) setUsernameValidation(validationState);
 54	      if (id === OpenstackSecretFieldsId.RegionName) setRegionNameValidation(validationState);
 55	      if (id === OpenstackSecretFieldsId.ProjectName) setProjectNameValidation(validationState);
 56	      if (id === OpenstackSecretFieldsId.DomainName) setDomainNameValidation(validationState);
 57	
 58	      const encodedValue = encode(value?.trim() ?? '');
 59	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 60	    },
 61	    [secret, onNewSecretChange],
 62	  );
 63	
 64	  const onClickTogglePassword = () => {
 65	    setPasswordHidden(!passwordHidden);
 66	  };
 67	
 68	  const onChangeFactory: onChangeFactoryType = (changedField) => (_e, value) => {
 69	    handleChange(changedField as OpenstackSecretFieldsId, value);
 70	  };
 71	
 72	  return (
 73	    <>
 74	      <OpenstackUsernameEditItem
 75	        usernameValidation={usernameValidation}
 76	        username={username}
 77	        onChangeFactory={onChangeFactory}
 78	      />
 79	
 80	      <FormGroupWithHelpText
 81	        label={t('Token')}
 82	        isRequired
 83	        fieldId={OpenstackSecretFieldsId.Token}
 84	        helperText={tokenValidation.msg}
 85	        helperTextInvalid={tokenValidation.msg}
 86	        validated={tokenValidation.type}
 87	      >
 88	        <InputGroup>
 89	          <TextInput
 90	            spellCheck="false"
 91	            isRequired
 92	            type={passwordHidden ? 'password' : 'text'}
 93	            id={OpenstackSecretFieldsId.Token}
 94	            name={OpenstackSecretFieldsId.Token}
 95	            value={token}
 96	            onChange={onChangeFactory(OpenstackSecretFieldsId.Token)}
 97	            validated={tokenValidation.type}
 98	          />
 99	          <Button
100	            variant={ButtonVariant.control}
101	            onClick={onClickTogglePassword}
102	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
103	          >
104	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
105	          </Button>
106	        </InputGroup>
107	      </FormGroupWithHelpText>
108	
109	      <OpenstackRegionEditItem
110	        regionNameValidation={regionNameValidation}
111	        regionName={regionName}
112	        onChangeFactory={onChangeFactory}
113	      />
114	
115	      <OpenstackProjectEditItem
116	        projectNameValidation={projectNameValidation}
117	        projectName={projectName}
118	        onChangeFactory={onChangeFactory}
119	      />
120	
121	      <OpenstackDomainEditItem
122	        domainNameValidation={domainNameValidation}
123	        domainName={domainName}
124	        onChangeFactory={onChangeFactory}
125	      />
126	    </>
127	  );
128	};
129	
130	export default TokenWithUsernameSecretFieldsEditSection;

